import{_ as s,o as e,c as t,a6 as i}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"Accounts and Wallets","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/software/accounts-wallets.md","filePath":"mainchain/software/accounts-wallets.md"}'),n={name:"mainchain/software/accounts-wallets.md"};function o(l,a,c,r,h,p){return e(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="accounts-and-wallets" tabindex="-1">Accounts and Wallets <a class="header-anchor" href="#accounts-and-wallets" aria-label="Permalink to &quot;Accounts and Wallets&quot;">​</a></h1><p>The <code>und</code> CMD can be used to create new accounts, or import previous accounts and keys.</p><h4 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h4><nav class="table-of-contents"><ul><li><a href="#prerequisites">Prerequisites</a></li><li><a href="#create-a-new-account">Create a new account</a></li><li><a href="#import-an-account">Import an account</a></li><li><a href="#list-show-accounts">List &amp; show accounts</a></li></ul></nav><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before continuing, ensure you have gone through the following docs:</p><ol><li><a href="./installation.html">Installing the software</a></li></ol><h2 id="create-a-new-account" tabindex="-1">Create a new account <a class="header-anchor" href="#create-a-new-account" aria-label="Permalink to &quot;Create a new account&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">IMPORTANT</p><p>When you create a new account, the CMD will output a mnemonic. KEEP THIS SAFE - if you lose it, you will not be able to recover your account!</p></div><p>To create a new account, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [account_name]</span></span></code></pre></div><p><code>[account_name]</code> is whatever name you would like to use as an identifier when signing transactions. For example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_new_wallet</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>stick to alphanumeric characters, hyphens, underscores and full stops.</p></div><p>If your OS keyring for <code>und</code> is not already unlocked/created, you will be prompted for a password. Once entered, the application will output your account details, including your wallet address, public key and mnemonic for recovery/future importing.</p><p>Accounts and keys are stored in your OS keyring by default.</p><h2 id="import-an-account" tabindex="-1">Import an account <a class="header-anchor" href="#import-an-account" aria-label="Permalink to &quot;Import an account&quot;">​</a></h2><p>The same command can be used to import a previously saved mnemonic by passing the <code>--recover</code> flag:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [account_name] --recover</span></span></code></pre></div><p>You will be prompted to enter your mnemonic.</p><h2 id="list-show-accounts" tabindex="-1">List &amp; show accounts <a class="header-anchor" href="#list-show-accounts" aria-label="Permalink to &quot;List &amp; show accounts&quot;">​</a></h2><p>You can list locally stored account with the following command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>or show the details of a particular account:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_new_wallet</span></span></code></pre></div><p>Run <code>und keys --help</code> for further details</p>',26)])])}const k=s(n,[["render",o]]);export{u as __pageData,k as default};
